#include <bits/stdc++.h>
using namespace std;

void backtrack(int idx, vector<int> &a, int x, vector<int> &subset, vector<vector<int>> &ans) {
    if(idx == a.size()) { // No more integers to consider
        int sum = 0;
        for(auto &x: subset) {
            sum += x;
        }
        if(sum == x) {
            ans.push_back(subset);
        }
        return;
    }
    backtrack(idx + 1, a, x, subset, ans); // Dont take the i-th integer

    subset.push_back(a[idx]);
    backtrack(idx + 1, a, x, subset, ans); // Take the i-th integer
    subset.pop_back();
}

vector<vector<int>> subset_sum(vector<int> a, int x) {
    vector<int> subset; // Creating an empty subset
    vector<vector<int>> ans; // To store all the subsets

    backtrack(0, a, x, subset, ans);

    return ans;
}

int main() {
    int n, x;
    cin >> n >> x;
    vector<int> a(n);
    for(auto &x: a) cin >> x;

    vector<vector<int>> subsets = subset_sum(a, x);
    for(auto &x: subsets) sort(x.begin(), x.end());
    sort(subsets.begin(), subsets.end());

    for(auto &x: subsets) {
        for(auto &y: x) {
            cout << y << " ";
        }
        cout << "\n";
    }
}

