    def backtrack(idx, subset, target):
        if target == 0:
            ans.append(subset.copy())
            return

        for i in range(idx, len(a)):
            if a[i] <= target:
                subset.append(a[i])
                backtrack(i + 1, subset, target - a[i])
                subset.pop()

    ans = []
    a.sort()
    backtrack(0, [], x)
