void backtrack(int idx, int a[], int x, int subset[], int j, int n)
{
    if (idx == n)
    { // No more integers to consider
        int sum = 0;
        for (int i = 0; i < j; i++)
        {
            sum += subset[i];
        }
        if (sum == x)
        {
            for (int i = 0; i < j; i++)
            {
                printf("%d ", subset[i]);
            }
            printf("\n");
        }
        return;
    }
    subset[j] = a[idx];
    backtrack(idx + 1, a, x, subset, j + 1, n); // Take the i-th integer
    backtrack(idx + 1, a, x, subset, j, n);     // Don't take the i-th integer
}

void subset_sum(int a[], int x, int n)
{
    int subsets[n];
    backtrack(0, a, x, subsets, 0, n);
}

int comp(const void *elem1, const void *elem2)
{
    int f = *((int *)elem1);
    int s = *((int *)elem2);
    if (f > s) return 1;
    if (f < s) return -1;
    return 0;
}

